import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useSocket } from '../../context/SocketContext';
import { getTheme, cardStyle } from '../../utils/theme';
import { PageHeader, Btn } from '../../components/common/UI';
import API from '../../utils/api';

const ICE_SERVERS = {
  iceServers: [
    { urls: 'stun:stun.l.google.com:19302' },
    { urls: 'stun:stun1.l.google.com:19302' },
  ],
};

export default function PatientVideoCall() {
  const { user, darkMode } = useAuth();
  const { socket } = useSocket();
  const t = getTheme(darkMode);

  const [phase, setPhase] = useState('lobby');
  const [muted, setMuted] = useState(false);
  const [videoOff, setVideoOff] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const [roomId, setRoomId] = useState(null);
  const [peerConnected, setPeerConnected] = useState(false);
  const [statusMsg, setStatusMsg] = useState('');
  const [debugInfo, setDebugInfo] = useState(''); // For debugging

  const localVideoRef = useRef(null);
  const remoteVideoRef = useRef(null);
  const localStreamRef = useRef(null);
  const pcRef = useRef(null);
  const timerRef = useRef(null);
  const isInitiatorRef = useRef(false);

  const fmt = (s) => `${String(Math.floor(s / 60)).padStart(2, '0')}:${String(s % 60).padStart(2, '0')}`;

  // Debug logger
  const addDebug = (msg) => {
    console.log('[DEBUG]', msg);
    setDebugInfo(prev => prev + '\n' + new Date().toLocaleTimeString() + ': ' + msg);
  };

  // ── Peer Connection Setup ──────────────────────────────────────────────────
  const createPeerConnection = useCallback(() => {
    addDebug('Creating peer connection');
    const pc = new RTCPeerConnection(ICE_SERVERS);

    pc.onicecandidate = ({ candidate }) => {
      if (candidate && socket && roomId) {
        socket.emit('webrtc:ice-candidate', { roomId, candidate });
      }
    };

    pc.ontrack = ({ streams }) => {
      addDebug('Received remote track');
      if (remoteVideoRef.current && streams[0]) {
        remoteVideoRef.current.srcObject = streams[0];
        setPeerConnected(true);
        setStatusMsg('Doctor connected ✓');
        addDebug('Remote video attached');
      }
    };

    pc.onconnectionstatechange = () => {
      addDebug(`Connection state: ${pc.connectionState}`);
      if (pc.connectionState === 'disconnected' || pc.connectionState === 'failed') {
        setStatusMsg('Connection lost. Reconnecting…');
        setPeerConnected(false);
      }
    };

    return pc;
  }, [socket, roomId]);

  // ── Test Local Video Display ────────────────────────────────────────────────
  const testLocalVideo = () => {
    addDebug('Testing local video display...');
    if (localVideoRef.current) {
      addDebug('Local video element found');
      if (localStreamRef.current) {
        addDebug('Stream exists, checking tracks...');
        const videoTracks = localStreamRef.current.getVideoTracks();
        addDebug(`Video tracks: ${videoTracks.length}`);
        videoTracks.forEach((track, i) => {
          addDebug(`Track ${i}: enabled=${track.enabled}, readyState=${track.readyState}, label=${track.label}`);
        });
        addDebug(`Stream active: ${localStreamRef.current.active}`);
      } else {
        addDebug('No stream found!');
      }
    } else {
      addDebug('Local video element NOT found!');
    }
  };

  // ── Start Call ──────────────────────────────────────────────────────────────
  const startCall = async () => {
    try {
      addDebug('========== STARTING CALL ==========');
      setStatusMsg('Requesting camera & microphone…');

      addDebug('Requesting media devices...');
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { width: { ideal: 1280 }, height: { ideal: 720 } }, 
        audio: true 
      });

      addDebug(`Got stream, active: ${stream.active}`);
      addDebug(`Video tracks: ${stream.getVideoTracks().length}`);
      addDebug(`Audio tracks: ${stream.getAudioTracks().length}`);

      stream.getVideoTracks().forEach((track, i) => {
        addDebug(`Video track ${i}: ${track.label}, enabled: ${track.enabled}, readyState: ${track.readyState}`);
        track.enabled = true;
      });

      localStreamRef.current = stream;

      // Method 1: Direct assignment
      if (localVideoRef.current) {
        addDebug('Setting srcObject on video element');
        localVideoRef.current.srcObject = stream;
        localVideoRef.current.muted = true;
        localVideoRef.current.volume = 0;

        // Try to play
        try {
          await localVideoRef.current.play();
          addDebug('Video play() successful');
        } catch (playErr) {
          addDebug(`Video play() failed: ${playErr.message}`);
        }

        // Check if video is actually displaying
        setTimeout(() => {
          addDebug(`Video readyState: ${localVideoRef.current?.readyState}`);
          addDebug(`Video paused: ${localVideoRef.current?.paused}`);
          addDebug(`Video srcObject: ${!!localVideoRef.current?.srcObject}`);
        }, 1000);
      } else {
        addDebug('ERROR: localVideoRef.current is null!');
      }

      // Create room on backend
      addDebug('Creating room on backend...');
      const { data } = await API.post('/webrtc/room');
      const newRoomId = data.roomId;
      addDebug(`Room created: ${newRoomId}`);
      setRoomId(newRoomId);

      // Create peer connection
      const pc = createPeerConnection();
      stream.getTracks().forEach(track => {
        addDebug(`Adding track to peer connection: ${track.kind}`);
        pc.addTrack(track, stream);
      });
      pcRef.current = pc;

      // Join signaling room
      if (socket) {
        addDebug('Joining signaling room...');
        socket.emit('webrtc:join', { roomId: newRoomId, userId: user._id, role: 'patient' });
      }

      setPhase('waiting');
      setStatusMsg('Room created. Share your Room ID with the doctor.');
      timerRef.current = setInterval(() => setElapsed(e => e + 1), 1000);

      addDebug('========== CALL STARTED ==========');
    } catch (e) {
      addDebug(`ERROR: ${e.message}`);
      console.error('Camera access error:', e);
      alert('Camera/microphone access required: ' + e.message);
    }
  };

  // ── Join Existing Room ──────────────────────────────────────────────────────
  const joinRoom = async (rid) => {
    try {
      addDebug(`Joining room: ${rid}`);
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });

      stream.getVideoTracks().forEach(track => track.enabled = true);
      localStreamRef.current = stream;

      if (localVideoRef.current) {
        localVideoRef.current.srcObject = stream;
        await localVideoRef.current.play();
      }

      const pc = createPeerConnection();
      stream.getTracks().forEach(track => pc.addTrack(track, stream));
      pcRef.current = pc;

      setRoomId(rid);
      if (socket) socket.emit('webrtc:join', { roomId: rid, userId: user._id, role: 'patient' });
      setPhase('in-call');
      timerRef.current = setInterval(() => setElapsed(e => e + 1), 1000);
    } catch (e) { 
      addDebug(`Join error: ${e.message}`);
      alert('Error joining room: ' + e.message); 
    }
  };

  // ── End Call ────────────────────────────────────────────────────────────────
  const endCall = () => {
    addDebug('Ending call');
    localStreamRef.current?.getTracks().forEach(t => {
      addDebug(`Stopping track: ${t.kind}`);
      t.stop();
    });
    pcRef.current?.close();
    if (socket && roomId) socket.emit('webrtc:leave', { roomId });
    if (timerRef.current) clearInterval(timerRef.current);
    pcRef.current = null;
    setPhase('ended');
    setMuted(false); 
    setVideoOff(false); 
    setElapsed(0);
    setPeerConnected(false);
    setStatusMsg('');
  };

  // Toggle mute
  const toggleMute = () => {
    const newMutedState = !muted;
    addDebug(`Toggling mute: ${newMutedState ? 'muted' : 'unmuted'}`);
    localStreamRef.current?.getAudioTracks().forEach(track => { 
      track.enabled = !newMutedState;
      addDebug(`Audio track enabled: ${track.enabled}`);
    });
    if (socket && roomId) {
      socket.emit('webrtc:toggle-media', { roomId, audio: !newMutedState, video: !videoOff });
    }
    setMuted(newMutedState);
  };

  // Toggle video
  const toggleVideo = () => {
    const newVideoOffState = !videoOff;
    addDebug(`Toggling video: ${newVideoOffState ? 'off' : 'on'}`);
    localStreamRef.current?.getVideoTracks().forEach(track => { 
      track.enabled = !newVideoOffState;
      addDebug(`Video track enabled: ${track.enabled}`);
    });
    if (socket && roomId) {
      socket.emit('webrtc:toggle-media', { roomId, audio: !muted, video: !newVideoOffState });
    }
    setVideoOff(newVideoOffState);
  };

  // Cleanup
  useEffect(() => {
    return () => {
      endCall();
    };
  }, []);

  useEffect(() => {
    if (phase === 'waiting' && roomId) {
      setPhase('in-call');
    }
  }, [roomId, phase]);

  return (
    <div style={{ background: t.bg, minHeight: '100vh', padding: 24 }}>
      <div style={{ maxWidth: 960, margin: '0 auto' }}>
        <PageHeader title="🎥 Video Consultation" subtitle="Peer-to-peer encrypted video call" darkMode={darkMode} />

        {/* Debug Panel */}
        {debugInfo && phase !== 'lobby' && (
          <div style={{ 
            background: '#1e1e1e', 
            color: '#0f0', 
            fontFamily: 'monospace', 
            fontSize: 11, 
            padding: 10, 
            marginBottom: 16, 
            borderRadius: 8,
            maxHeight: 150,
            overflow: 'auto',
            whiteSpace: 'pre-wrap'
          }}>
            <strong>Debug Info:</strong>
            <div>{debugInfo}</div>
            <button 
              onClick={() => setDebugInfo('')} 
              style={{ marginTop: 8, background: '#333', color: '#fff', border: 'none', padding: '2px 8px', borderRadius: 4, cursor: 'pointer' }}
            >
              Clear
            </button>
            <button 
              onClick={testLocalVideo} 
              style={{ marginTop: 8, marginLeft: 8, background: '#333', color: '#fff', border: 'none', padding: '2px 8px', borderRadius: 4, cursor: 'pointer' }}
            >
              Test Video
            </button>
          </div>
        )}

        {/* LOBBY */}
        {phase === 'lobby' && (
          <div style={{ ...cardStyle(t), padding: 48, textAlign: 'center' }}>
            <div style={{ fontSize: '5rem', marginBottom: 20 }}>🎥</div>
            <h2 style={{ color: t.text, fontSize: 24, fontWeight: 800, marginBottom: 12 }}>Ready to Connect?</h2>
            <p style={{ color: t.textSub, marginBottom: 32, fontSize: 15 }}>
              Start a peer-to-peer WebRTC video consultation.<br />Your camera and microphone will be requested.
            </p>
            <Btn variant="primary" size="lg" onClick={startCall}>🎥 Start New Call</Btn>
          </div>
        )}

        {/* IN CALL */}
        {(phase === 'in-call' || phase === 'waiting') && (
          <div style={{ ...cardStyle(t), overflow: 'hidden' }}>
            {/* Status bar */}
            {statusMsg && (
              <div style={{ background: peerConnected ? '#dcfce7' : '#fef9c3', color: peerConnected ? '#166534' : '#854d0e', padding: '8px 16px', fontSize: 13, fontWeight: 600, textAlign: 'center' }}>
                {statusMsg}
              </div>
            )}

            {/* Room ID share */}
            {roomId && (
              <div style={{ padding: '10px 20px', background: darkMode ? '#1e293b' : '#f8fafc', borderBottom: `1px solid ${t.cardBorder}`, display: 'flex', alignItems: 'center', gap: 12, flexWrap: 'wrap' }}>
                <span style={{ color: t.textSub, fontSize: 13 }}>Room ID:</span>
                <code style={{ background: darkMode ? '#0f172a' : '#e0f2fe', color: '#0ea5e9', padding: '3px 10px', borderRadius: 6, fontSize: 12, fontFamily: 'monospace' }}>{roomId}</code>
                <button onClick={() => navigator.clipboard.writeText(roomId)} style={{ fontSize: 12, color: '#0ea5e9', background: 'none', border: 'none', cursor: 'pointer' }}>📋 Copy</button>
              </div>
            )}

            {/* Video grid */}
            <div style={{ background: '#0f172a', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 2, minHeight: 400 }}>
              {/* Local video */}
              <div style={{ position: 'relative', background: '#1e293b', display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: 300 }}>
                <video 
                  ref={localVideoRef} 
                  autoPlay 
                  playsInline
                  muted 
                  style={{ 
                    width: '100%', 
                    height: '100%', 
                    objectFit: 'cover', 
                    transform: 'scaleX(-1)', 
                    display: videoOff ? 'none' : 'block',
                    maxHeight: 400,
                    background: '#000'
                  }} 
                />
                {videoOff && (
                  <div style={{ color: 'white', textAlign: 'center' }}>
                    <div style={{ fontSize: '3rem' }}>📷</div>
                    <p style={{ fontSize: 13 }}>Camera off</p>
                  </div>
                )}
                {!videoOff && localStreamRef.current?.getVideoTracks()[0]?.enabled === false && (
                  <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', color: 'white', background: 'rgba(0,0,0,0.7)', padding: 8, borderRadius: 8 }}>
                    Camera blocked
                  </div>
                )}
                <div style={{ position: 'absolute', bottom: 10, left: 10, background: 'rgba(0,0,0,0.6)', color: 'white', fontSize: 12, padding: '3px 8px', borderRadius: 6 }}>
                  You {muted ? '🔇' : '🎙️'}
                </div>
              </div>

              {/* Remote video */}
              <div style={{ position: 'relative', background: '#0f172a', display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: 300 }}>
                <video 
                  ref={remoteVideoRef} 
                  autoPlay 
                  playsInline
                  style={{ 
                    width: '100%', 
                    height: '100%', 
                    objectFit: 'cover', 
                    maxHeight: 400, 
                    display: peerConnected ? 'block' : 'none',
                    background: '#000'
                  }} 
                />
                {!peerConnected && (
                  <div style={{ color: 'white', textAlign: 'center' }}>
                    <div style={{ fontSize: '3rem', marginBottom: 8 }}>👨‍⚕️</div>
                    <p style={{ fontSize: 13, color: '#94a3b8' }}>Waiting for doctor...</p>
                    <div style={{ width: 32, height: 32, border: '3px solid #0ea5e9', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '10px auto' }} />
                  </div>
                )}
                {peerConnected && (
                  <div style={{ position: 'absolute', bottom: 10, left: 10, background: 'rgba(0,0,0,0.6)', color: 'white', fontSize: 12, padding: '3px 8px', borderRadius: 6 }}>
                    Doctor 👨‍⚕️
                  </div>
                )}
              </div>
            </div>

            {/* Controls */}
            <div style={{ background: '#1e293b', padding: '16px 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 12 }}>
              <div style={{ color: '#94a3b8', fontSize: 14, fontFamily: 'monospace' }}>⏱️ {fmt(elapsed)}</div>
              <div style={{ display: 'flex', gap: 12 }}>
                <button onClick={toggleMute} style={{ width: 52, height: 52, borderRadius: '50%', border: 'none', background: muted ? '#ef4444' : 'rgba(255,255,255,0.15)', color: 'white', cursor: 'pointer', fontSize: 20 }}>
                  {muted ? '🔇' : '🎙️'}
                </button>
                <button onClick={toggleVideo} style={{ width: 52, height: 52, borderRadius: '50%', border: 'none', background: videoOff ? '#ef4444' : 'rgba(255,255,255,0.15)', color: 'white', cursor: 'pointer', fontSize: 20 }}>
                  {videoOff ? '📷' : '🎥'}
                </button>
                <button onClick={endCall} style={{ padding: '0 24px', height: 52, borderRadius: 26, border: 'none', background: '#ef4444', color: 'white', cursor: 'pointer', fontSize: 14, fontWeight: 700 }}>
                  📵 End Call
                </button>
              </div>
              <div style={{ color: peerConnected ? '#10b981' : '#f59e0b', fontSize: 13, fontWeight: 700 }}>
                {peerConnected ? '● Connected' : '○ Waiting'}
              </div>
            </div>
          </div>
        )}

        {/* ENDED */}
        {phase === 'ended' && (
          <div style={{ ...cardStyle(t), padding: 48, textAlign: 'center' }}>
            <div style={{ fontSize: '4rem', marginBottom: 16 }}>✅</div>
            <h2 style={{ color: t.text, fontWeight: 800, marginBottom: 8 }}>Call Ended</h2>
            <p style={{ color: t.textSub, marginBottom: 8 }}>Duration: {fmt(elapsed)}</p>
            <Btn variant="primary" onClick={() => { setPhase('lobby'); setElapsed(0); setRoomId(null); setPeerConnected(false); setDebugInfo(''); }}>
              Start New Call
            </Btn>
          </div>
        )}
        <style>{`
          @keyframes spin { 
            to { transform: rotate(360deg); } 
          }
        `}</style>
      </div>
    </div>
  );
}
